  const parsedUrl = new URL(url);
  const authRegex = /^https?:\/\/([^:]+):?([^@]+)?@/;

  if (parsedUrl.username || parsedUrl.password) {
    const match = parsedUrl.href.match(authRegex);
    if (match) {
      parsedUrl.username = match[1];
      parsedUrl.password = match[2];
